const raw = $json;
let output;

try {
  // Navigate to the nested string JSON output
  const text = raw.output?.[0]?.content?.[0]?.text || '';
  const parsed = JSON.parse(text);
  output = parsed.search_query;
} catch (e) {
  output = "fallback search query";
}

return [{ json: { keyword: output } }];

const items = $input.all();

// Extract the query from the item that contains it (likely has 'query' in it)
const queryItem = items.find(i => i.json.query);
const query = queryItem?.json.query || 'No query provided';

// Extract search results (those with title/snippet/url/content)
const searchResults = items
  .filter(i => i.json.content && i.json.title && i.json.url)
  .map((item, index) => ({
    id: index + 1,
    title: item.json.title || '',
    snippet: item.json.snippet || '',
    url: item.json.url || '',
    content: item.json.content || ''
  }));

// Public version without full content
const publicLinks = searchResults.map(({ id, title, snippet, url }) => ({
  id,
  title,
  snippet,
  url
}));

return [
  {
    json: {
      query,
      links: publicLinks,
      originalResults: searchResults
    }
  }
];

const fullResults = $items('Build Relevance Filter Input')[0].json.originalResults || [];
const query = $items('Build Relevance Filter Input')[0].json.query;
const topIds = $json.output.top_ids || [];

// Find matching pages by ID
const selectedPages = topIds.map(id => {
  const match = fullResults.find(r => r.id === id);
  return {
    title: match?.title || `Missing Title (ID: ${id})`,
    url: match?.url || `Missing URL (ID: ${id})`,
    content: match?.content || 'NO CONTENT FOUND',
