  };
});

return selectedPages.map(item => ({ json: item }));

const inputData = $('Get Initial Query').first().json.query || 'unknown';

const promptText = `You are a senior technical assistant specialized in crafting precise, natural-sounding Google search queries for developers and researchers.

The user has described a technical problem. Your task is to:
- Understand their goal thoroughly.
- Generate **one single, complete search query** written as a natural sentence.
- Think like a developer typing a realistic query into Google to solve a problem.
- Avoid keyword-stacking (e.g., "n8n youtube trigger monitor") — this is NOT helpful.
- Use clear, specific, and natural phrasing that includes key tools or APIs.
- Prioritize quality over brevity — it's okay if the query is 8–14 words long.

---

### ✅ Format: Always return JSON like this:

{
  "search_query": "realistic search phrase"
}

---

### 🧪 Few-Shot Examples:

**Example 1**  
User Input:  
"I want to connect a Google Sheet to a backend API and trigger updates when new rows are added. It should push the data to a Node.js Express server in real time."  
Output:
{
  "search_query": "google sheets webhook to Node.js Express server real-time update"
}

---

**Example 2**  
User Input:  
"I'm building a chatbot using LangChain and OpenAI. How can I let it search the web before answering user questions?"  
Output:
{
  "search_query": "langchain web search tool OpenAI agent integration"
}

---

**Example 3**  
User Input:  
"I want to automatically back up my PostgreSQL database every night to an AWS S3 bucket using a cron job."  
Output:
{
  "search_query": "postgresql nightly backup to AWS S3 using cron"
}

---

**Example 4**  
User Input:  
"I have an image which was AI generated and has a human face in it. I want to change the face in the image to my own face. Which is the best API provider to do this? I am looking for both open source and also paid API providers. I am also open to building my own self-hosted solution using open source tools available. Please let me know the best way forward."  
Output:
{
  "search_query": "face swap API or open source tool to replace face in image"
}

---

### 🔎 Now generate a query for this user input:

"""${inputData}"""

⚠️ Do not include explanations, markdown, line breaks, or trailing commas.
⚠️ Only return the JSON object exactly as shown above.

`;

return [
  {
    json: {
      model: "gpt-4.1",
      input: [
        {
          role: "system",
          content: [
            {
              type: "input_text",
              text: `User goal: ${inputData}`
            }
          ]
        },
        {
          role: "user",
          content: [
            {
              type: "input_text",
              text: promptText
            }
          ]
        }
      ],
      temperature: 0.7,
      top_p: 1,
      max_output_tokens: 512,
      text: {
        format: {
          type: "text"
        }
      },
      reasoning: {},
      tools: [
        {
          type: "web_search_preview",
          user_location: {
            type: "approximate"
          },
          search_context_size: "high"
        }
      ],
      store: true
    }
  }
];

return $input.all().flatMap(item => {
  const results = item.json.results || [];

  if (!Array.isArray(results)) return [];

  return results
    .filter(result => result.raw_content && result.raw_content.trim() !== '') // Filter out empty content
    .map(result => {
      return {
        json: {
          title: result.title || '',
          snippet: result.content || '', // Short description or summary
          url: result.url || '',
          content: result.raw_content || '' // ✅ Full raw content (most useful)
        },
      };
    });
});

const data = $json.output || $json;

return [{
  json: {
    question: data.question || '',
    search_query: data.search_query || '',
    answer: data.answer || '',
    sources: data.sources || []
  }
}];

