const rawItems = $input.all();

const items = rawItems.filter(item => {
  const data = item.json.output || item.json;
  return data && (data.question || data.loop2_search_query || data.loop2_answer || data.loop2_sources);
});

if (items.length === 0) return [];

let query = '';
let loop2_search_query = '';
let allAnswers = [];
let allSources = [];

// Go through each valid item
for (let i = 0; i < items.length; i++) {
  const data = items[i].json.output || items[i].json;

  // Extract question and search query once
  if (!query && data.question) {
    query = data.question;
  }
  if (!loop2_search_query && data.loop2_search_query) {
    loop2_search_query = data.loop2_search_query;
  }

  // Append Loop 2 answer
  if (data.loop2_answer) {
    allAnswers.push(`### 🧠 Loop 2 Answer:n${data.loop2_answer}`);
  }

  // Collect Loop 2 sources
  if (Array.isArray(data.loop2_sources)) {
    allSources.push(
      ...data.loop2_sources.map((src, j) => ({
        id: allSources.length + j + 1,
        title: src.title || '',
        url: src.url || ''
      }))
    );
  }
}

return [{
  json: {
    query,
    loop2_search_query,
    answer: allAnswers.join('nn'),
    sources: allSources
  }
}];

