const items = $input.all();

let result = {
  question: '',
  search_query: '',
  answer: '',
  sources: [],
  loop2_search_query: '',
  loop2_answer: '',
  loop2_sources: [],
  loop3_search_query: '',
  loop3_answer: '',
  loop3_sources: []
};

for (const item of items) {
  const data = item.json;

  if (data.question && data.search_query && data.answer && data.sources) {
    result.question = data.question;
    result.search_query = data.search_query;
    result.answer = data.answer;
    result.sources = data.sources;
  }

  if (data.loop2_search_query && data.loop2_answer && data.loop2_sources) {
    result.loop2_search_query = data.loop2_search_query;
    result.loop2_answer = data.loop2_answer;
    result.loop2_sources = data.loop2_sources;
  }

  if (data.loop3_search_query && data.loop3_answer && data.loop3_sources) {
    result.loop3_search_query = data.loop3_search_query;
    result.loop3_answer = data.loop3_answer;
    result.loop3_sources = data.loop3_sources;
  }
}

return [{ json: result }];

const data = $json.output || $json;

return [{
  json: {
    question: data.question || '',
    loop3_search_query: data.loop3_search_query || '',
    loop3_answer: data.loop3_answer || '',
    loop3_sources: data.loop3_sources || []
  }
}];

const rawItems = $input.all();
const items = rawItems.filter(item => {
  const data = item.json.output || item.json;
  return data && (data.answer || data.loop2_answer || data.loop3_answer || data.sources || data.question);
});

if (items.length === 0) return [];

let allSources = [];
let allAnswers = [];
let query = '';

for (let i = 0; i < items.length; i++) {
  const data = items[i].json.output || item.json;

  if (!query && data.question) {
    query = data.question;
  }

  // Append answers from each loop with labels
  if (data.answer) {
    allAnswers.push(`### Loop 1 Answer:n${data.answer}`);
  }

  if (data.loop2_answer) {
    allAnswers.push(`### Loop 2 Answer:n${data.loop2_answer}`);
  }

  if (data.loop3_answer) {
    allAnswers.push(`### Loop 3 Answer:n${data.loop3_answer}`);
  }

  // Combine all sources
  if (Array.isArray(data.sources)) {
    allSources.push(
      ...data.sources.map((src, j) => ({
        id: allSources.length + j + 1,
        title: src.title || '',
        url: src.url || ''
      }))
    );
  }
}

return [{
  json: {
    query,
    answer: allAnswers.join('nn'),
    sources: allSources
  }
}];
